// 교육용 빅뱅 시뮬레이션 - 중앙 핵과 주변 입자들의 결합 과정
import * as THREE from "three";

/**
 * 쿼크-글루온 플라즈마 단계 (10^-12초)
 * 중앙에서 뜨거운 쿼크-글루온 플라즈마가 형성되고, 주변에서 입자들이 모여든다
 */
export function createQuarkGluonPlasma(numParticles = 500000) {
  const group = new THREE.Group();

  // 중앙 쿼크-글루온 플라즈마 (핵처럼 표현)
  const coreGeometry = new THREE.BufferGeometry();
  const numCoreParticles = 50000;
  const corePositions = new Float32Array(numCoreParticles * 3);
  const coreColors = new Float32Array(numCoreParticles * 3);

  // 중앙 코어에 쿼크-글루온 입자들 배치
  for (let i = 0; i < numCoreParticles; i++) {
    const r = Math.random() * 100;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;
    corePositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    corePositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    corePositions[i * 3 + 2] = r * Math.cos(phi);

    // 극도로 뜨거운 상태: 흰색/밝은 색
    const type = Math.random();
    if (type < 0.5) {
      coreColors[i * 3] = 1.0;
      coreColors[i * 3 + 1] = 1.0;
      coreColors[i * 3 + 2] = 1.0;
    } else {
      coreColors[i * 3] = 1.0;
      coreColors[i * 3 + 1] = 0.8;
      coreColors[i * 3 + 2] = 0.2;
    }
  }
  coreGeometry.setAttribute("position", new THREE.BufferAttribute(corePositions, 3));
  coreGeometry.setAttribute("color", new THREE.BufferAttribute(coreColors, 3));
  const coreMaterial = new THREE.PointsMaterial({
    size: 1.5,
    vertexColors: true,
    sizeAttenuation: true
  });
  const corePoints = new THREE.Points(coreGeometry, coreMaterial);
  group.add(corePoints);

  // 주변에서 모여드는 입자들 (바깥쪽)
  const surroundingGeometry = new THREE.BufferGeometry();
  const numSurrounding = numParticles - numCoreParticles;
  const surroundingPositions = new Float32Array(numSurrounding * 3);
  const surroundingColors = new Float32Array(numSurrounding * 3);
  const velocities = new Float32Array(numSurrounding * 3);
  for (let i = 0; i < numSurrounding; i++) {
    // 중앙을 향해 모여드는 입자들
    const r = 300 + Math.random() * 700;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;
    surroundingPositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    surroundingPositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    surroundingPositions[i * 3 + 2] = r * Math.cos(phi);

    // 중앙을 향한 속도
    const centerVec = new THREE.Vector3(-surroundingPositions[i * 3], -surroundingPositions[i * 3 + 1], -surroundingPositions[i * 3 + 2]).normalize();
    velocities[i * 3] = centerVec.x * 8;
    velocities[i * 3 + 1] = centerVec.y * 8;
    velocities[i * 3 + 2] = centerVec.z * 8;

    // 쿼크 색상
    const type = Math.random();
    if (type < 0.3) {
      surroundingColors[i * 3] = 1.0;
      surroundingColors[i * 3 + 1] = 0.2;
      surroundingColors[i * 3 + 2] = 0.2;
    } else if (type < 0.6) {
      surroundingColors[i * 3] = 0.2;
      surroundingColors[i * 3 + 1] = 1.0;
      surroundingColors[i * 3 + 2] = 0.2;
    } else if (type < 0.85) {
      surroundingColors[i * 3] = 0.2;
      surroundingColors[i * 3 + 1] = 0.2;
      surroundingColors[i * 3 + 2] = 1.0;
    } else {
      surroundingColors[i * 3] = 1.0;
      surroundingColors[i * 3 + 1] = 1.0;
      surroundingColors[i * 3 + 2] = 0.2;
    }
  }
  surroundingGeometry.setAttribute("position", new THREE.BufferAttribute(surroundingPositions, 3));
  surroundingGeometry.setAttribute("color", new THREE.BufferAttribute(surroundingColors, 3));
  const surroundingMaterial = new THREE.PointsMaterial({
    size: 1.2,
    vertexColors: true,
    sizeAttenuation: true
  });
  const surroundingPoints = new THREE.Points(surroundingGeometry, surroundingMaterial);
  surroundingPoints.userData.velocities = velocities;
  surroundingPoints.userData.positions = surroundingPositions;
  group.add(surroundingPoints);
  return {
    group,
    corePositions,
    surroundingPositions,
    velocities
  };
}

/**
 * 쿼크 결합 단계 (10^-6초)
 * 중앙에 형성된 하드론, 주변에서 쿼크들이 모여들어 결합된다
 */
export function createQuarkCombination(stageProgress) {
  const group = new THREE.Group();

  // 중앙에 형성된 하드론 (양성자/중성자) - 핵처럼
  const hadronCoreGeometry = new THREE.BufferGeometry();
  const numHadrons = 100000;
  const hadronPositions = new Float32Array(numHadrons * 3);
  const hadronColors = new Float32Array(numHadrons * 3);
  for (let i = 0; i < numHadrons; i++) {
    const r = 80 * stageProgress; // 진행에 따라 핵이 커짐
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;
    hadronPositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    hadronPositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    hadronPositions[i * 3 + 2] = r * Math.cos(phi);
    const isProton = Math.random() > 0.5;
    if (isProton) {
      hadronColors[i * 3] = 1.0;
      hadronColors[i * 3 + 1] = 0.2;
      hadronColors[i * 3 + 2] = 0.2;
    } else {
      hadronColors[i * 3] = 0.2;
      hadronColors[i * 3 + 1] = 0.2;
      hadronColors[i * 3 + 2] = 1.0;
    }
  }
  hadronCoreGeometry.setAttribute("position", new THREE.BufferAttribute(hadronPositions, 3));
  hadronCoreGeometry.setAttribute("color", new THREE.BufferAttribute(hadronColors, 3));
  const hadronMaterial = new THREE.PointsMaterial({
    size: 3 + stageProgress * 2,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.5 + stageProgress * 0.5
  });
  const hadronPoints = new THREE.Points(hadronCoreGeometry, hadronMaterial);
  group.add(hadronPoints);

  // 주변에서 모여드는 쿼크들
  const quarkGeometry = new THREE.BufferGeometry();
  const numQuarks = 200000;
  const quarkPositions = new Float32Array(numQuarks * 3);
  const quarkColors = new Float32Array(numQuarks * 3);
  for (let i = 0; i < numQuarks; i++) {
    // 초반: 먼 곳에서, 진행됨: 가까워짐
    const maxDistance = 600 * (1 - stageProgress) + 150 * stageProgress;
    const r = maxDistance * (0.3 + Math.random() * 0.7);
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;
    quarkPositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    quarkPositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    quarkPositions[i * 3 + 2] = r * Math.cos(phi);

    // 쿼크 색상
    const type = i % 3;
    if (type === 0) {
      quarkColors[i * 3] = 1.0;
      quarkColors[i * 3 + 1] = 0.1 + stageProgress * 0.3;
      quarkColors[i * 3 + 2] = 0.1 + stageProgress * 0.3;
    } else if (type === 1) {
      quarkColors[i * 3] = 0.1 + stageProgress * 0.3;
      quarkColors[i * 3 + 1] = 1.0;
      quarkColors[i * 3 + 2] = 0.1 + stageProgress * 0.3;
    } else {
      quarkColors[i * 3] = 0.1 + stageProgress * 0.3;
      quarkColors[i * 3 + 1] = 0.1 + stageProgress * 0.3;
      quarkColors[i * 3 + 2] = 1.0;
    }
  }
  quarkGeometry.setAttribute("position", new THREE.BufferAttribute(quarkPositions, 3));
  quarkGeometry.setAttribute("color", new THREE.BufferAttribute(quarkColors, 3));
  const quarkMaterial = new THREE.PointsMaterial({
    size: 1.5 + stageProgress * 1,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 1 - stageProgress * 0.3
  });
  const quarkPoints = new THREE.Points(quarkGeometry, quarkMaterial);
  group.add(quarkPoints);
  return group;
}

/**
 * 핵융합 단계 (1-3분)
 * 중앙에 형성된 가벼운 원자핵(He, Li, Be), 주변에서 양성자/중성자가 모여든다
 */
export function createNucleosynthesis(stageProgress) {
  const group = new THREE.Group();

  // 중앙에 형성된 핵들
  const nucleiCoreGeometry = new THREE.BufferGeometry();
  const numNuclei = 150000;
  const nucleiPositions = new Float32Array(numNuclei * 3);
  const nucleiColors = new Float32Array(numNuclei * 3);
  for (let i = 0; i < numNuclei; i++) {
    // 진행에 따라 더 큰 핵 형성
    const r = 120 * stageProgress;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;
    nucleiPositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    nucleiPositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    nucleiPositions[i * 3 + 2] = r * Math.cos(phi);

    // 핵의 종류
    const nucleusType = i % 3;
    if (nucleusType === 0) {
      // 헬륨-4: 시안색
      nucleiColors[i * 3] = 0.2;
      nucleiColors[i * 3 + 1] = 0.8 + stageProgress * 0.2;
      nucleiColors[i * 3 + 2] = 1.0;
    } else if (nucleusType === 1) {
      // 리튬: 초록색
      nucleiColors[i * 3] = 0.2 + stageProgress * 0.3;
      nucleiColors[i * 3 + 1] = 1.0;
      nucleiColors[i * 3 + 2] = 0.2;
    } else {
      // 베릴륨: 노란색
      nucleiColors[i * 3] = 1.0;
      nucleiColors[i * 3 + 1] = 1.0;
      nucleiColors[i * 3 + 2] = 0.2;
    }
  }
  nucleiCoreGeometry.setAttribute("position", new THREE.BufferAttribute(nucleiPositions, 3));
  nucleiCoreGeometry.setAttribute("color", new THREE.BufferAttribute(nucleiColors, 3));
  const nucleiMaterial = new THREE.PointsMaterial({
    size: 4 + stageProgress * 2,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.5 + stageProgress * 0.5
  });
  const nucleiPoints = new THREE.Points(nucleiCoreGeometry, nucleiMaterial);
  group.add(nucleiPoints);

  // 주변에서 모여드는 양성자/중성자
  const pnGeometry = new THREE.BufferGeometry();
  const numPN = 200000;
  const pnPositions = new Float32Array(numPN * 3);
  const pnColors = new Float32Array(numPN * 3);
  for (let i = 0; i < numPN; i++) {
    // 주변에서 중앙으로 모여드는 중
    const maxDistance = 700 * (1 - stageProgress) + 200 * stageProgress;
    const r = maxDistance * (0.3 + Math.random() * 0.7);
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;
    pnPositions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    pnPositions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    pnPositions[i * 3 + 2] = r * Math.cos(phi);

    // 양성자 vs 중성자
    if (Math.random() > 0.5) {
      pnColors[i * 3] = 1.0;
      pnColors[i * 3 + 1] = 0.1;
      pnColors[i * 3 + 2] = 0.1;
    } else {
      pnColors[i * 3] = 0.1;
      pnColors[i * 3 + 1] = 0.1;
      pnColors[i * 3 + 2] = 1.0;
    }
  }
  pnGeometry.setAttribute("position", new THREE.BufferAttribute(pnPositions, 3));
  pnGeometry.setAttribute("color", new THREE.BufferAttribute(pnColors, 3));
  const pnMaterial = new THREE.PointsMaterial({
    size: 2.5,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 1 - stageProgress * 0.4
  });
  const pnPoints = new THREE.Points(pnGeometry, pnMaterial);
  group.add(pnPoints);
  return group;
}

/**
 * 원자 형성 단계 (38만년)
 * 중앙에 핵, 주변에 전자들이 궤도를 형성하면서 중성 원자 완성
 */
export function createAtomFormation(stageProgress) {
  const group = new THREE.Group();

  // 중앙 핵들 (많은 수의 원자 핵)
  const nucleusGeometry = new THREE.BufferGeometry();
  const numAtomNuclei = 100000;
  const nucleusPositions = new Float32Array(numAtomNuclei * 3);
  const nucleusColors = new Float32Array(numAtomNuclei * 3);

  // 핵들의 위치 저장 (전자 궤도 계산용)
  const nucleusCenters = [];
  for (let i = 0; i < numAtomNuclei; i++) {
    // 중앙에 분포
    const r = 150 * stageProgress;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;
    const nx = r * Math.sin(phi) * Math.cos(theta);
    const ny = r * Math.sin(phi) * Math.sin(theta);
    const nz = r * Math.cos(phi);
    nucleusPositions[i * 3] = nx;
    nucleusPositions[i * 3 + 1] = ny;
    nucleusPositions[i * 3 + 2] = nz;
    nucleusCenters.push({
      x: nx,
      y: ny,
      z: nz
    });

    // 핵: 노란색
    nucleusColors[i * 3] = 1.0;
    nucleusColors[i * 3 + 1] = 0.8;
    nucleusColors[i * 3 + 2] = 0.1;
  }
  nucleusGeometry.setAttribute("position", new THREE.BufferAttribute(nucleusPositions, 3));
  nucleusGeometry.setAttribute("color", new THREE.BufferAttribute(nucleusColors, 3));
  const nucleusMaterial = new THREE.PointsMaterial({
    size: 5 + stageProgress * 2,
    vertexColors: true,
    sizeAttenuation: true
  });
  const nucleusPoints = new THREE.Points(nucleusGeometry, nucleusMaterial);
  group.add(nucleusPoints);

  // 전자 구름 - 핵 주변을 도는 전자들
  const electronGeometry = new THREE.BufferGeometry();
  const numElectrons = 150000;
  const electronPositions = new Float32Array(numElectrons * 3);
  const electronColors = new Float32Array(numElectrons * 3);
  let eIdx = 0;
  for (let i = 0; i < numAtomNuclei && eIdx < numElectrons; i++) {
    const center = nucleusCenters[i];

    // 이 원자의 전자 개수 (수소 1개, 헬륨 2개)
    const numE = Math.random() > 0.3 ? 2 : 1;
    for (let e = 0; e < numE && eIdx < numElectrons; e++) {
      // 전자 궤도
      const orbitRadius = 80 + (numE === 2 ? 50 : 0);

      // 궤도 상의 각도
      const angle = e / numE * Math.PI * 2 + Math.random() * 0.3;

      // 3D 궤도 (Bohr 모델)
      const orbitalAngle = Math.acos(Math.random() * 2 - 1);

      // 시간에 따라 전자 위치 진동 (orbiting effect)
      const time = Date.now() * 0.001;
      const phaseShift = time * (e + 1) * 0.5;
      const finalRadius = orbitRadius * stageProgress;
      electronPositions[eIdx * 3] = center.x + Math.sin(orbitalAngle) * Math.cos(angle + phaseShift) * finalRadius;
      electronPositions[eIdx * 3 + 1] = center.y + Math.sin(orbitalAngle) * Math.sin(angle + phaseShift) * finalRadius;
      electronPositions[eIdx * 3 + 2] = center.z + Math.cos(orbitalAngle) * finalRadius;

      // 전자: 청록색
      electronColors[eIdx * 3] = 0.2 + stageProgress * 0.4;
      electronColors[eIdx * 3 + 1] = 0.9 + stageProgress * 0.1;
      electronColors[eIdx * 3 + 2] = 1.0;
      eIdx++;
    }
  }
  electronGeometry.setAttribute("position", new THREE.BufferAttribute(electronPositions.slice(0, eIdx * 3), 3));
  electronGeometry.setAttribute("color", new THREE.BufferAttribute(electronColors.slice(0, eIdx * 3), 3));
  const electronMaterial = new THREE.PointsMaterial({
    size: 2 + stageProgress * 1.5,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.3 + stageProgress * 0.5
  });
  const electronPoints = new THREE.Points(electronGeometry, electronMaterial);
  group.add(electronPoints);
  return group;
}

